// Helper function to trim whitespace from a string
std::string trim(const std::string& str) {
    std::string s = str;
    s.erase(s.begin(), std::find_if(s.begin(), s.end(), [](unsigned char ch) {
        return !std::isspace(ch);
    }));
    s.erase(std::find_if(s.rbegin(), s.rend(), [](unsigned char ch) {
        return !std::isspace(ch);
    }).base(), s.end());
    return s;
}

// This function simulates running the student's main function with given input
// and returns the captured output.
// In a real evaluation system, the student's code (with its own main)
// would be compiled into an executable and run as a separate child process.
// The input string would be fed to its stdin, and its stdout would be captured.
// For the purpose of this driver, we illustrate the I/O redirection mechanism.
// The actual execution of the student's `main` function would occur here.
// For instance, if the student's `main` was renamed to `student_solution_main()`:
// extern int student_solution_main(); // Declaration if linked
// student_solution_main();            // Call
std::string run_student_code_and_capture_output(const std::string& input) {
    std::stringstream ss_input(input);
    std::stringstream ss_output;

    // Save original cin/cout buffers
    std::streambuf* old_cin_buf = std::cin.rdbuf();
    std::streambuf* old_cout_buf = std::cout.rdbuf();

    // Redirect cin to ss_input, cout to ss_output
    std::cin.rdbuf(ss_input.rdbuf());
    std::cout.rdbuf(ss_output.rdbuf());

    // --- CONCEPTUAL EXECUTION OF STUDENT'S MAIN ---
    // In a real testing environment, the student's compiled executable
    // would be launched as a child process here, with its stdin/stdout
    // connected to pipes that are managed by this driver.
    // For this C++ snippet, imagine the student's `main` function is executed.
    // Example: `int student_program_exit_code = system("./student_executable");`
    // Or, if student's main was renamed: `student_solution_main();`

    // Restore original cin/cout buffers
    std::cin.rdbuf(old_cin_buf);
    std::cout.rdbuf(old_cout_buf);

    return trim(ss_output.str());
}
